import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Card, Chip, icon } from 'decantr/components';

code.example:
function StatusBoard({ services }) {
  const { div, span, h2, h3 } = tags;
  const statusColor = s => s === 'operational' ? '_bgsuccess' : s === 'degraded' ? '_bgwarning' : '_bgerror';
  const allOk = services.every(s => s.status === 'operational');

  return div({ class: css('_flex _col _gap4') },
    div({ class: css('_flex _aic _jcsb') },
      h2({ class: css('_heading4') }, 'System Status'),
      Badge({ variant: allOk ? 'success' : 'warning' }, allOk ? 'All Operational' : 'Issues Detected')
    ),
    div({ class: css('_grid _gcaf280 _gap4') },
      ...services.map(svc =>
        Card({},
          Card.Body({ class: css('_flex _col _gap3 _p4') },
            div({ class: css('_flex _aic _jcsb') },
              div({ class: css('_flex _aic _gap2') },
                div({ class: css(`_w[10px] _h[10px] _rfull ${statusColor(svc.status)}`) }),
                h3({ class: css('_textsm _bold') }, svc.name)
              ),
              Chip({ label: svc.status, size: 'xs', variant: svc.status === 'operational' ? 'success' : svc.status === 'degraded' ? 'warning' : 'error' })
            ),
            div({ class: css('_flex _jcsb _textxs _fgmuted') },
              span({}, `Uptime: ${svc.uptime}`),
              span({}, `Last check: ${svc.lastCheck}`)
            )
          )
        )
      )
    )
  );
}
